import{_ as t,o as n,c as o,a8 as i}from"./chunks/framework.DvHWw5tv.js";const g=JSON.parse('{"title":"mengyue-components","description":"","frontmatter":{},"headers":[],"relativePath":"en/plugin/mengyueComponents.md","filePath":"en/plugin/mengyueComponents.md"}'),a={name:"en/plugin/mengyueComponents.md"};function r(s,e,l,d,c,p){return n(),o("div",{"data-pagefind-body":!0,"data-pagefind-meta":"date:1776410922000"},[...e[0]||(e[0]=[i('<h1 id="mengyue-components" tabindex="-1">mengyue-components <a class="header-anchor" href="#mengyue-components" aria-label="Permalink to “mengyue-components”">​</a></h1><p><code>mengyue-components</code> is the <strong>official version</strong> of this component library. Building upon the full capabilities of the early transitional version, it features a unified API design and refined quality, making it the recommended production-grade component solution.</p><h2 id="core-features" tabindex="-1">Core Features <a class="header-anchor" href="#core-features" aria-label="Permalink to “Core Features”">​</a></h2><ul><li><strong>Vue 3 + TypeScript</strong>: Leverage the Composition API and type inference to provide complete TS type definitions.</li><li><strong>No Third-Party Dependencies</strong>: All components are self-developed and implemented, with highly controllable styles and logic, avoiding version bundling of external libraries.</li><li><strong>100% Test Coverage</strong>: With over 200 unit test cases, ensuring the functional boundaries and interaction behaviors of each component are stable and reliable.</li><li><strong>Lightweight Packaging</strong>: The full import size is less than 1MB, and it natively supports on-demand loading, posing almost no burden on project size.</li></ul><p>Differences from earlier versions</p><p>Compared to the transitional version <code>mengyue-plus</code>, <code>mengyue-components</code> has made the following key improvements:</p><ul><li><strong>Unified Props API</strong>: Streamlined and standardized the naming and usage of all component properties to reduce learning and memorization costs.</li><li><strong>Defect Fixing</strong>: Known issues accumulated in early versions were addressed in a concentrated manner, further enhancing code robustness.</li><li><strong>Long-term Maintenance and Support</strong>: As an official release, it will continue to receive feature iterations, performance optimizations, and community feedback fixes.</li></ul><p>On the functional level, the two are completely equivalent, with the <strong>official version representing a thorough refinement and standardization of the early version</strong>.</p><h2 id="applicable-scenarios" tabindex="-1">Applicable Scenarios <a class="header-anchor" href="#applicable-scenarios" aria-label="Permalink to “Applicable Scenarios”">​</a></h2><p><code>mengyue-components</code> is suitable for all backend systems, tool-type products, and lightweight web applications built with Vue 3 + TypeScript. Its lightweight and minimalist design philosophy makes it particularly ideal for projects with high demands on code size or customization flexibility.</p><h2 id="getting-started" tabindex="-1">Getting Started <a class="header-anchor" href="#getting-started" aria-label="Permalink to “Getting Started”">​</a></h2><p>For installation and import methods, please refer to the <a href="./../components/FastStart.html">Quick Start</a> section.<br> If you have previously used <code>mengyue-plus</code>, you can refer to the <a href="./../question/migration.html">Migration Guide</a> to complete the operation. <a href="./../plus/FastStart.html">Click here</a> to view the documentation.</p>',12)])])}const u=t(a,[["render",r]]);export{g as __pageData,u as default};
